UPDATE J09C_temp
SET ENTSCHEIDUNG = (
  SELECT CASE WHEN COUNT(DISTINCT EQUNR) < 3 THEN 'KSA' ELSE 'EVU' END
  FROM J09C_temp t2
  WHERE t2.HAUS = J09C_temp.HAUS
);

UPDATE J09C_temp
SET TITLE = (
  SELECT s.TITLE FROM sales_master s WHERE s.EQUNR = J09C_temp.EQUNR LIMIT 1
),
FORENAME = (
  SELECT s.FORENAME FROM sales_master s WHERE s.EQUNR = J09C_temp.EQUNR LIMIT 1
),
SURNAME = (
  SELECT s.SURNAME FROM sales_master s WHERE s.EQUNR = J09C_temp.EQUNR LIMIT 1
),
STREET = (
  SELECT s.STREET FROM sales_master s WHERE s.EQUNR = J09C_temp.EQUNR LIMIT 1
),
STREETNO = (
  SELECT s.STREETNO FROM sales_master s WHERE s.EQUNR = J09C_temp.EQUNR LIMIT 1
),
CITY1_cust = (
  SELECT s.CITY1 FROM sales_master s WHERE s.EQUNR = J09C_temp.EQUNR LIMIT 1
),
CITY2_cust = (
  SELECT s.CITY2 FROM sales_master s WHERE s.EQUNR = J09C_temp.EQUNR LIMIT 1
),
POST_CODE1_cust = (
  SELECT s.POST_CODE1 FROM sales_master s WHERE s.EQUNR = J09C_temp.EQUNR LIMIT 1
),
EMAIL = (
  SELECT s.EMAIL FROM sales_master s WHERE s.EQUNR = J09C_temp.EQUNR LIMIT 1
);

UPDATE J09C_temp
SET TITLE = COALESCE(TITLE, (
  SELECT n.TITLE FROM net_master n WHERE n.EQUNR = J09C_temp.EQUNR LIMIT 1
)),
FORENAME = COALESCE(FORENAME, (
  SELECT n.FORENAME FROM net_master n WHERE n.EQUNR = J09C_temp.EQUNR LIMIT 1
)),
SURNAME = COALESCE(SURNAME, (
  SELECT n.SURNAME FROM net_master n WHERE n.EQUNR = J09C_temp.EQUNR LIMIT 1
)),
STREET = COALESCE(STREET, (
  SELECT n.STREET FROM net_master n WHERE n.EQUNR = J09C_temp.EQUNR LIMIT 1
)),
STREETNO = COALESCE(STREETNO, (
  SELECT n.STREETNO FROM net_master n WHERE n.EQUNR = J09C_temp.EQUNR LIMIT 1
)),
CITY1_cust = COALESCE(CITY1_cust, (
  SELECT n.CITY1 FROM net_master n WHERE n.EQUNR = J09C_temp.EQUNR LIMIT 1
)),
CITY2_cust = COALESCE(CITY2_cust, (
  SELECT n.CITY2 FROM net_master n WHERE n.EQUNR = J09C_temp.EQUNR LIMIT 1
)),
POST_CODE1_cust = COALESCE(POST_CODE1_cust, (
  SELECT n.POST_CODE1 FROM net_master n WHERE n.EQUNR = J09C_temp.EQUNR LIMIT 1
)),
EMAIL = COALESCE(EMAIL, (
  SELECT n.EMAIL FROM net_master n WHERE n.EQUNR = J09C_temp.EQUNR LIMIT 1
));
